def factorial(n):
    if n == 0:
        return 1
    else:
        return n * factorial(n - 1)

def count_zeros(n):
    zeros = 0
    while n % 10 == 0:
        zeros += 1
        n //= 10
    return zeros

def main():
    n, b = map(int, input().split())
    fact = factorial(n)
    zeros = count_zeros(fact)
    print(zeros)

if __name__ == '__main__':
    main()
